module RefModule(
    input clk,          // Chip clock signal.
    input rst_n,        // Active-low reset signal.
    input en,           // Enable signal to allow counting.
    input load,         // Load signal to load the counter value.
    input [3:0] load_val, // 4-bit input value to be loaded into the counter.

    output [3:0] count  // 4-bit count value.
);

reg [3:0] unused_count_r;

//------------------------------------------------
// Counter logic
always @(posedge clk or negedge rst_n)
    if (!rst_n) unused_count_r <= 4'd0;  // Reset counter
    else if (load) unused_count_r <= load_val; // Load counter
    else if (en) begin
        if (unused_count_r == 4'd0) unused_count_r <= 4'd15; // Wrap around
        else unused_count_r <= unused_count_r - 1'b1;        // Decrement counter
    end

assign count = unused_count_r;

endmodule
